function process(value: string | number) {
  if (typeof value === 'string') {
    // TypeScript knows 'value' is a string here
    console.log(value.toUpperCase());
  } else {
    // Here, 'value' is a number
    console.log(value.toFixed(2));
  }
}

process('hello'); // Outputs: HELLO
process(3.14159); // Outputs: 3.14

interface Admin {
  role: 'admin';
  permissions: string[];
}

interface Guest {
  role: 'guest';
  visitingFor: string;
}

type User = Admin | Guest;

function isAdmin(user: User): user is Admin {
  return user.role === 'admin';
}

function handleUser(user: User) {
  if (isAdmin(user)) {
    // user is narrowed to Admin
    console.log('Admin permissions:', user.permissions.join(', '));
  } else {
    // user is Guest
    console.log('Guest visiting for:', user.visitingFor);
  }
}

function printLength(str: string | null | undefined) {
  if (str && typeof str === 'string') {
    console.log('Length:', str.length);
  } else {
    console.log('No valid string provided');
  }
}

printLength('Hello'); // Length: 5
printLength(null);    // No valid string provided

type Fish = { swim: () => void };
type Bird = { fly: () => void };

function move(animal: Fish | Bird) {
  if ('swim' in animal) {  // Basic type guard
    animal.swim();
  } else {
    animal.fly();
  }
}

function isFish(animal: Fish | Bird): animal is Fish {
  return (animal as Fish).swim !== undefined;
}

function move(animal: Fish | Bird) {
  if (isFish(animal)) {
    animal.swim();  // TypeScript now knows animal is Fish
  } else {
    animal.fly();
  }
}

type Shape =
  | { kind: 'circle'; radius: number }
  | { kind: 'square'; sideLength: number };

function area(shape: Shape) {
  switch (shape.kind) {
    case 'circle':
      return Math.PI * shape.radius ** 2;
    case 'square':
      return shape.sideLength ** 2;
  }
}

class ManagedResource:
    def __enter__(self):
        print('Acquiring resource')
        return self

